use std::any::Any;

pub trait Message: Send + 'static {}

pub trait Actor: Send + 'static {
    type Msg: Message;

    fn receive(&mut self, msg: Self::Msg, ctx: &mut Context<Self>)
    where
        Self: Sized;
}

use tokio::sync::mpsc;

pub struct ActorRef<A: Actor> {
    sender: mpsc::Sender<A::Msg>,
}

impl<A: Actor> ActorRef<A> {
    pub async fn send(&self, msg: A::Msg) -> Result<(), SendError> {
        self.sender.send(msg).await.map_err(|_| SendError::Disconnected)
    }
}
